17	// CSRFHeaderName is the HTTP header that must carry the server-issued CSRF
18	// token on operatorPromptSubmit calls (FEAT operator-prompts, Story 15).
19	const CSRFHeaderName = "X-CSRF-Token"
20	
21	// OperatorPromptIdempotencyTTL is the window during which duplicate
22	// idempotency keys deduplicate to the original bead.
23	const OperatorPromptIdempotencyTTL = 24 * time.Hour
24	
25	// OperatorPromptEventKind is the BeadEvent.Kind appended to every
26	// operator-prompt bead's audit log on submit, capturing the originating
27	// identity (localhost OR ts-net WhoIs).
28	const OperatorPromptEventKind = "operator_prompt_submit"
29	
30	// httpRequestKey is the context key used by the server to plumb the
31	// originating *http.Request into GraphQL resolver calls so the resolver can
32	// validate CSRF tokens and capture the originating identity.
33	type httpRequestKey struct{}
34	
35	// WithHTTPRequest returns ctx with r attached for downstream resolver access.
36	// The server's GraphQL HTTP handler must call this before delegating to the
37	// gqlgen handler so resolvers that depend on request headers (CSRF token,
38	// X-Tailscale-User) work correctly.
39	func WithHTTPRequest(ctx context.Context, r *http.Request) context.Context {
40		return context.WithValue(ctx, httpRequestKey{}, r)
41	}
42	
43	// httpRequestFromContext retrieves the *http.Request previously attached via
44	// WithHTTPRequest, or nil if none was set.
45	func httpRequestFromContext(ctx context.Context) *http.Request {
46		if v, ok := ctx.Value(httpRequestKey{}).(*http.Request); ok {
47			return v
48		}
49		return nil
50	}
51	
52	// CSRFTokenStore validates a CSRF token presented on a write request. The
53	// production implementation stores a per-process token issued at server
54	// startup and rotated via an explicit endpoint; tests inject a stub.
55	type CSRFTokenStore interface {
56		Validate(token string) bool
57	}
58	
59	// IdempotencyCache deduplicates operatorPromptSubmit calls by key within
60	// OperatorPromptIdempotencyTTL. Lookup returns the original bead ID stored
61	// under key (and true) when the key was previously seen and has not expired,
62	// or "", false otherwise. Store records key -> beadID at submit time.
63	type IdempotencyCache interface {
64		Lookup(key string) (string, bool)
65		Store(key, beadID string)
66	}
67	
68	// MemoryIdempotencyCache is a process-local in-memory IdempotencyCache with
69	// TTL-based eviction. It is safe for concurrent use.
70	type MemoryIdempotencyCache struct {
71		mu  sync.Mutex
72		now func() time.Time
73		ttl time.Duration
74		m   map[string]idempotencyEntry
75	}
76	
77	type idempotencyEntry struct {
78		beadID    string
79		expiresAt time.Time
80	}
81	
82	// NewMemoryIdempotencyCache constructs a cache with the operator-prompt
83	// default 24h TTL and the real wall clock.
84	func NewMemoryIdempotencyCache() *MemoryIdempotencyCache {
85		return &MemoryIdempotencyCache{
86			now: time.Now,
87			ttl: OperatorPromptIdempotencyTTL,
88			m:   make(map[string]idempotencyEntry),
89		}
90	}
91	
92	// Lookup returns the bead ID associated with key when present and unexpired.
93	func (c *MemoryIdempotencyCache) Lookup(key string) (string, bool) {
94		if key == "" {
95			return "", false
96		}
97		c.mu.Lock()
98		defer c.mu.Unlock()
99		e, ok := c.m[key]
100		if !ok {
101			return "", false
102		}
103		if c.now().After(e.expiresAt) {
104			delete(c.m, key)
105			return "", false
106		}
107		return e.beadID, true
108	}
109	
110	// Store records key -> beadID with the configured TTL window.
111	func (c *MemoryIdempotencyCache) Store(key, beadID string) {
112		if key == "" {
113			return
114		}
115		c.mu.Lock()
116		defer c.mu.Unlock()
117		c.m[key] = idempotencyEntry{beadID: beadID, expiresAt: c.now().Add(c.ttl)}
118	}
119	
120	// StaticCSRFTokenStore is a single-secret CSRFTokenStore — the token is
121	// generated once at server startup and validated by constant-time compare.
122	type StaticCSRFTokenStore struct {
123		token string
124	}
125	
126	// NewStaticCSRFTokenStore returns a store seeded with a freshly-generated
127	// 32-byte random token.
128	func NewStaticCSRFTokenStore() (*StaticCSRFTokenStore, error) {
129		var buf [32]byte
130		if _, err := rand.Read(buf[:]); err != nil {
131			return nil, fmt.Errorf("csrf: generate token: %w", err)
132		}
133		return &StaticCSRFTokenStore{token: hex.EncodeToString(buf[:])}, nil
134	}
135	
136	// NewStaticCSRFTokenStoreWithToken constructs a store using the supplied
137	// token (used by tests so a deterministic header value can be sent).
138	func NewStaticCSRFTokenStoreWithToken(token string) *StaticCSRFTokenStore {
139		return &StaticCSRFTokenStore{token: token}
140	}
141	
142	// Token returns the stored CSRF token (used by the server to expose it via a
143	// dedicated endpoint or embed it in served HTML).
144	func (s *StaticCSRFTokenStore) Token() string { return s.token }
145	
146	// Validate compares presented to the stored token using a length-equal
147	// constant-time check.
148	func (s *StaticCSRFTokenStore) Validate(presented string) bool {
149		if presented == "" || len(presented) != len(s.token) {
150			return false
151		}
152		var diff byte
153		for i := 0; i < len(s.token); i++ {
154			diff |= s.token[i] ^ presented[i]
155		}
156		return diff == 0
157	}
158	
159	// errCSRF is returned by OperatorPromptSubmit when the CSRF check fails.
160	// The HTTP transport for the GraphQL endpoint surfaces this as a 403; the
161	// resolver itself only emits the error.
162	var errCSRF = errors.New("operator-prompts: CSRF token missing or invalid (status: 403)")
163	
164	// OperatorPromptSubmit implements the operatorPromptSubmit mutation: it
165	// validates the CSRF token from the request header, deduplicates within a
166	// 24h window by idempotency key, and (on first submission) creates a new
167	// operator-prompt bead in the proposed status with an audit event capturing
168	// the originating identity (localhost user OR ts-net WhoIs).
169	func (r *mutationResolver) OperatorPromptSubmit(ctx context.Context, input OperatorPromptSubmitInput) (*OperatorPromptSubmitResult, error) {
170		if r.WorkingDir == "" {
171			return nil, fmt.Errorf("working directory not configured")
172		}
173		if strings.TrimSpace(input.Prompt) == "" {
174			return nil, fmt.Errorf("operator-prompts: prompt is required")
175		}
176		if strings.TrimSpace(input.IdempotencyKey) == "" {
177			return nil, fmt.Errorf("operator-prompts: idempotency key is required")
178		}
179	
180		httpReq := httpRequestFromContext(ctx)
181		if httpReq == nil {
182			// No request context means we cannot enforce CSRF, which is the
183			// whole point of the gate. Refuse rather than fail open.
184			return nil, errCSRF
185		}
186		presented := httpReq.Header.Get(CSRFHeaderName)
187		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
188			return nil, errCSRF
189		}
190	
191		cache := r.OperatorPromptIdempotency
192		if cache == nil {
193			return nil, fmt.Errorf("operator-prompts: idempotency cache not configured")
194		}
195	
196		store := r.beadStore()
197		if id, ok := cache.Lookup(input.IdempotencyKey); ok {
198			existing, err := store.Get(id)
199			if err == nil {
200				return &OperatorPromptSubmitResult{
201					Bead:         beadModelFromBead(existing),
202					Deduplicated: true,
203				}, nil
204			}
205			// Cached ID points to a missing bead — fall through and create a
206			// fresh bead, overwriting the stale entry below.
207		}
208	
209		tier := bead.DefaultPriority
210		if input.Tier != nil {
211			tier = *input.Tier
212		}
213		b := bead.NewOperatorPromptBead(input.Prompt, tier)
214		if err := store.Create(b); err != nil {
215			return nil, err
216		}
217	
218		identity := operatorPromptIdentity(httpReq)
219		auditBody := fmt.Sprintf(
220			"identity=%s remote_addr=%s tailscale_user=%s tailscale_node=%s idempotency_key=%s",
221			identity.kind,
222			httpReq.RemoteAddr,
223			httpReq.Header.Get("X-Tailscale-User"),
224			httpReq.Header.Get("X-Tailscale-Node"),
225			input.IdempotencyKey,
226		)
227		if err := store.AppendEvent(b.ID, bead.BeadEvent{
228			Kind:    OperatorPromptEventKind,
229			Summary: "operator prompt submitted",
230			Body:    auditBody,
231			Actor:   identity.actor,
232			Source:  "graphql:operatorPromptSubmit",
233		}); err != nil {
234			return nil, fmt.Errorf("operator-prompts: append audit event: %w", err)
235		}
236	
237		cache.Store(input.IdempotencyKey, b.ID)
238	
239		// Re-read so the audit event materializes in the returned snapshot.
240		persisted, err := store.Get(b.ID)
241		if err != nil {
242			return nil, err
243		}
244		return &OperatorPromptSubmitResult{
245			Bead:         beadModelFromBead(persisted),
246			Deduplicated: false,
247		}, nil
248	}
249	
250	type operatorPromptIdentityInfo struct {
251		kind  string // "tsnet" or "localhost"
252		actor string
253	}
254	
255	// operatorPromptIdentity classifies the originating identity for audit
256	// logging. ts-net peers are identified by the X-Tailscale-User header
257	// injected by tsnetMiddleware; loopback callers fall back to a
258	// "localhost:<remote-addr>" actor string. A bare "anonymous" actor is used
259	// only when neither signal is present (which should not occur because
260	// requireTrusted gates the GraphQL endpoint).
261	func operatorPromptIdentity(r *http.Request) operatorPromptIdentityInfo {
262		if user := r.Header.Get("X-Tailscale-User"); user != "" {
263			return operatorPromptIdentityInfo{kind: "tsnet", actor: user}
264		}
265		if r.RemoteAddr != "" {
266			return operatorPromptIdentityInfo{kind: "localhost", actor: "localhost:" + r.RemoteAddr}
267		}
268		return operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
269	}
