298	func mustDeduplicated(t *testing.T, resp map[string]json.RawMessage) bool {
299		t.Helper()
300		var data struct {
301			OperatorPromptSubmit struct {
302				Deduplicated bool `json:"deduplicated"`
303			} `json:"operatorPromptSubmit"`
304		}
305		if err := json.Unmarshal(resp["data"], &data); err != nil {
306			t.Fatalf("parse: %v", err)
